Batch-regret-based parallel insertion with capacity-proportional candidate scoring and incremental feasibility checks, prioritizing orders with earliest time windows first and using a regret threshold to decide between inserting into existing assigns versus spawning new ones.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type Order struct {
		idx     int
		timeWin int
		load    int
	}
	orders := make([]Order, len(oris))
	for i := 0; i < len(oris); i++ {
		winLength := oris[i].TimeEnd - oris[i].TimeStart
		if winLength <= 0 {
			winLength = 1
		}
		orders[i] = Order{idx: i, timeWin: oris[i].TimeStart*10000/winLength, load: oris[i].Load}
	}
	for i := 0; i < len(orders)-1; i++ {
		for j := i + 1; j < len(orders); j++ {
			if orders[i].timeWin > orders[j].timeWin || (orders[i].timeWin == orders[j].timeWin && orders[i].load > orders[j].load) {
				orders[i], orders[j] = orders[j], orders[i]
			}
		}
	}
	availAssigns := make([]int, 0, MAXASSIGNS)
	assignLoads := make(map[int]int)
	for i := 0; i < dispatch.AssignsLen; i++ {
		availAssigns = append(availAssigns, i)
		assignLoads[i] = 0
	}
	regretThreshold := 3.0
	capacityWeight := 0.7
	penaltyFactor := 1e6
	for _, ord := range orders {
		idx := ord.idx
		ori := oris[idx]
		des := dess[idx]
		shipID := total_ship + idx
		type Candidate struct {
			assignIdx       int
			score           float64
			feasible        bool
			deltaCost       float64
			newCost         float64
		}
		candidates := make([]Candidate, 0, len(availAssigns)+1)
		for _, ai := range availAssigns {
			oldCost := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(shipID, ori, des)
			var deltaCost float64
			var newCost float64
			var feasible bool
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost = dispatch.Assigns[ai].Cost
				if newCost >= 0 && newCost < penaltyFactor/2 {
					feasible = true
					deltaCost = newCost - oldCost
				}
				dispatch.Assigns[ai].RemoveShip(shipID)
				dispatch.Assigns[ai].GenRoute()
			}
			if !feasible {
				candidates = append(candidates, Candidate{assignIdx: ai, score: -1, feasible: false})
				continue
			}
			capScore := 1.0 / (float64(assignLoads[ai]+ord.load+1) * capacityWeight)
			incrScore := 1.0 / (deltaCost + 1.0)
			finalScore := capScore + incrScore
			candidates = append(candidates, Candidate{assignIdx: ai, score: finalScore, feasible: true, deltaCost: deltaCost, newCost: newCost})
		}
		sort.SliceStable(candidates, func(i, j int) bool {
			if candidates[i].feasible != candidates[j].feasible {
				return candidates[i].feasible
			}
			return candidates[i].score > candidates[j].score
		})
		inserted := false
		if len(candidates) > 0 && candidates[0].feasible {
			bestAi := candidates[0].assignIdx
			dispatch.Assigns[bestAi].AddShip(shipID, ori, des)
			dispatch.Assigns[bestAi].GenRoute()
			assignLoads[bestAi] += ord.load
			inserted = true
			if len(candidates) > 1 && candidates[1].feasible {
				regret := candidates[1].score - candidates[0].score
				if regret > regretThreshold && dispatch.AssignsLen < MAXASSIGNS {
					dispatch.Assigns[bestAi].RemoveShip(shipID)
					dispatch.Assigns[bestAi].GenRoute()
					assignLoads[bestAi] -= ord.load
					inserted = false
				}
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				ok := dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
						dispatch.AssignsLen++
						availAssigns = append(availAssigns, newIdx)
						assignLoads[newIdx] = ord.load
						inserted = true
					} else {
						dispatch.Assigns[newIdx].RemoveShip(shipID)
						dispatch.Assigns[newIdx].GenRoute()
					}
				}
			}
			if !inserted && len(candidates) > 0 && candidates[0].feasible {
				bestAi := candidates[0].assignIdx
				dispatch.Assigns[bestAi].AddShip(shipID, ori, des)
				dispatch.Assigns[bestAi].GenRoute()
				assignLoads[bestAi] += ord.load
				inserted = true
			}
		}
		if !inserted && len(candidates) > 0 {
			for _, cand := range candidates {
				if cand.feasible {
					dispatch.Assigns[cand.assignIdx].AddShip(shipID, ori, des)
					dispatch.Assigns[cand.assignIdx].GenRoute()
					assignLoads[cand.assignIdx] += ord.load
					break
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

