			}
			finalAssign := &dispatch.Assigns[chosenIdx]
			finalAssign.AddShip(total_ship+jj, oris[jj], dess[jj])
			finalAssign.GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

